// MCP state needs connection storage:
let activeConnection: SQL | null = null

// db.connect tool:
export function registerDbConnect(server: FastMCP) {
  server.addTool({
    name: 'db.connect',
    execute: async (args) => {
      const { connectionString } = args
      activeConnection = await Bun.sql(connectionString)
      return JSON.stringify({ ok: true, connected: true })
    }
  })
}
